import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation, useParams } from "wouter";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { useToast } from "@/hooks/use-toast";
import TopNav from "@/components/TopNav";
import type { GolfPool, GolfPoolEntry, GolfTournament } from "@shared/schema";
import { ArrowLeft, Plus, Users, Calendar, Trophy, CircleDot, Settings, Trash2, Play, Pause, Check, X } from "lucide-react";
import { format } from "date-fns";

type PoolWithDetails = GolfPool & {
  entries: GolfPoolEntry[];
  tournaments: GolfTournament[];
};

export default function GolfPoolManager() {
  const [, setLocation] = useLocation();
  const params = useParams();
  const poolId = params.id || "";
  const { toast } = useToast();
  const [showAddEntryDialog, setShowAddEntryDialog] = useState(false);
  const [newEntryName, setNewEntryName] = useState("");
  const [newEntryEmail, setNewEntryEmail] = useState("");

  const { data: pool, isLoading } = useQuery<PoolWithDetails>({
    queryKey: ["/api/golf/pools", poolId],
    queryFn: async () => {
      const response = await fetch(`/api/golf/pools/${poolId}`);
      if (!response.ok) throw new Error("Failed to fetch pool");
      return response.json();
    },
  });

  const { data: tournaments = [] } = useQuery<GolfTournament[]>({
    queryKey: ["/api/golf/tournaments", pool?.season],
    queryFn: async () => {
      const response = await fetch(`/api/golf/tournaments?season=${pool?.season}`);
      if (!response.ok) throw new Error("Failed to fetch tournaments");
      return response.json();
    },
    enabled: !!pool?.season,
  });

  const updatePoolMutation = useMutation({
    mutationFn: async (data: Partial<GolfPool>) => {
      return await apiRequest("PATCH", `/api/golf/pools/${poolId}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/golf/pools", poolId] });
      toast({ title: "Pool Updated" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const addEntryMutation = useMutation({
    mutationFn: async (data: { entryName: string; email: string }) => {
      return await apiRequest("POST", `/api/golf/pools/${poolId}/entries`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/golf/pools", poolId] });
      toast({ title: "Entry Added" });
      setShowAddEntryDialog(false);
      setNewEntryName("");
      setNewEntryEmail("");
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const updateEntryMutation = useMutation({
    mutationFn: async ({ entryId, data }: { entryId: string; data: { status: string } }) => {
      return await apiRequest("PATCH", `/api/golf/entries/${entryId}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/golf/pools", poolId] });
      toast({ title: "Entry Updated" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const deletePoolMutation = useMutation({
    mutationFn: async () => {
      return await apiRequest("DELETE", `/api/golf/pools/${poolId}`);
    },
    onSuccess: () => {
      toast({ title: "Pool Deleted" });
      setLocation("/admin/golf");
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const handleStatusChange = (newStatus: string) => {
    updatePoolMutation.mutate({ status: newStatus as any });
  };

  const handleWeekChange = (week: string) => {
    updatePoolMutation.mutate({ currentWeek: parseInt(week) });
  };

  const handleAddEntry = () => {
    if (newEntryName && newEntryEmail) {
      addEntryMutation.mutate({ entryName: newEntryName, email: newEntryEmail });
    }
  };

  const handleEliminateEntry = (entryId: string) => {
    updateEntryMutation.mutate({ entryId, data: { status: "eliminated" } });
  };

  const handleReinstateEntry = (entryId: string) => {
    updateEntryMutation.mutate({ entryId, data: { status: "active" } });
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background">
        <TopNav title="Golf Survivor" />
        <main className="max-w-6xl mx-auto px-6 py-8">
          <p className="text-muted-foreground">Loading...</p>
        </main>
      </div>
    );
  }

  if (!pool) {
    return (
      <div className="min-h-screen bg-background">
        <TopNav title="Golf Survivor" />
        <main className="max-w-6xl mx-auto px-6 py-8">
          <p className="text-destructive">Pool not found</p>
        </main>
      </div>
    );
  }

  const activeEntries = pool.entries?.filter((e) => e.status === "active") || [];
  const eliminatedEntries = pool.entries?.filter((e) => e.status === "eliminated") || [];
  const currentTournament = tournaments.find((t) => t.weekNumber === pool.currentWeek);

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "upcoming":
        return <Badge variant="secondary">Upcoming</Badge>;
      case "active":
        return <Badge className="bg-green-600 text-white">Active</Badge>;
      case "completed":
        return <Badge variant="outline">Completed</Badge>;
      default:
        return <Badge variant="secondary">{status}</Badge>;
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <TopNav title="Golf Survivor" />

      <main className="max-w-6xl mx-auto px-6 py-8">
        <div className="mb-6">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setLocation("/admin/golf")}
            className="mb-4"
            data-testid="button-back"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Dashboard
          </Button>

          <div className="flex items-start justify-between gap-4">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <h2 className="text-3xl font-semibold">{pool.name}</h2>
                {getStatusBadge(pool.status)}
              </div>
              <p className="text-muted-foreground">
                {pool.season} Season - Week {pool.currentWeek}
                {currentTournament && ` - ${currentTournament.name}`}
              </p>
            </div>

            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button variant="outline" size="sm" data-testid="button-delete-pool">
                  <Trash2 className="h-4 w-4 mr-2" />
                  Delete Pool
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Delete Pool?</AlertDialogTitle>
                  <AlertDialogDescription>
                    This will permanently delete this pool and all its entries. This cannot be undone.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={() => deletePoolMutation.mutate()}
                    className="bg-destructive text-destructive-foreground"
                    data-testid="button-confirm-delete"
                  >
                    Delete
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </div>

        <div className="grid gap-6 md:grid-cols-3 mb-8">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">Status</CardTitle>
            </CardHeader>
            <CardContent>
              <Select value={pool.status} onValueChange={handleStatusChange}>
                <SelectTrigger data-testid="select-pool-status">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="upcoming">Upcoming</SelectItem>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="completed">Completed</SelectItem>
                </SelectContent>
              </Select>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">Current Week</CardTitle>
            </CardHeader>
            <CardContent>
              <Select value={pool.currentWeek?.toString()} onValueChange={handleWeekChange}>
                <SelectTrigger data-testid="select-current-week">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {Array.from({ length: 35 }, (_, i) => i + 1).map((week) => {
                    const tournament = tournaments.find((t) => t.weekNumber === week);
                    return (
                      <SelectItem key={week} value={week.toString()}>
                        Week {week}{tournament ? ` - ${tournament.name}` : ""}
                      </SelectItem>
                    );
                  })}
                </SelectContent>
              </Select>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">Entries</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-4">
                <div className="text-2xl font-bold">{activeEntries.length}</div>
                <span className="text-sm text-muted-foreground">active</span>
                {eliminatedEntries.length > 0 && (
                  <>
                    <div className="text-2xl font-bold text-muted-foreground">{eliminatedEntries.length}</div>
                    <span className="text-sm text-muted-foreground">eliminated</span>
                  </>
                )}
              </div>
            </CardContent>
          </Card>
        </div>

        <Card className="mb-8">
          <CardHeader className="flex flex-row items-center justify-between gap-2">
            <div>
              <CardTitle>Pool Entries</CardTitle>
              <CardDescription>
                Manage participants in this survivor pool
              </CardDescription>
            </div>
            <Dialog open={showAddEntryDialog} onOpenChange={setShowAddEntryDialog}>
              <DialogTrigger asChild>
                <Button size="sm" data-testid="button-add-entry">
                  <Plus className="h-4 w-4 mr-2" />
                  Add Entry
                </Button>
              </DialogTrigger>
              <DialogContent>
                <DialogHeader>
                  <DialogTitle>Add Entry</DialogTitle>
                  <DialogDescription>
                    Add a new participant to this pool
                  </DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div>
                    <label className="text-sm font-medium">Entry Name</label>
                    <Input
                      value={newEntryName}
                      onChange={(e) => setNewEntryName(e.target.value)}
                      placeholder="e.g., John's Entry"
                      data-testid="input-entry-name"
                    />
                  </div>
                  <div>
                    <label className="text-sm font-medium">Email</label>
                    <Input
                      type="email"
                      value={newEntryEmail}
                      onChange={(e) => setNewEntryEmail(e.target.value)}
                      placeholder="email@example.com"
                      data-testid="input-entry-email"
                    />
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setShowAddEntryDialog(false)}>
                    Cancel
                  </Button>
                  <Button
                    onClick={handleAddEntry}
                    disabled={!newEntryName || !newEntryEmail || addEntryMutation.isPending}
                    data-testid="button-submit-entry"
                  >
                    {addEntryMutation.isPending ? "Adding..." : "Add Entry"}
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </CardHeader>
          <CardContent>
            {pool.entries?.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                No entries yet. Add your first participant above.
              </div>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Entry Name</TableHead>
                    <TableHead>Email</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Used Golfers</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {pool.entries?.map((entry) => (
                    <TableRow key={entry.id} data-testid={`row-entry-${entry.id}`}>
                      <TableCell className="font-medium">{entry.entryName}</TableCell>
                      <TableCell>{entry.email}</TableCell>
                      <TableCell>
                        {entry.status === "active" ? (
                          <Badge className="bg-green-600 text-white">Active</Badge>
                        ) : (
                          <Badge variant="destructive">
                            Eliminated (Week {entry.eliminatedWeek})
                          </Badge>
                        )}
                      </TableCell>
                      <TableCell>
                        <span className="text-muted-foreground text-sm">
                          {(entry.usedGolfers as string[] || []).length} golfers
                        </span>
                      </TableCell>
                      <TableCell className="text-right">
                        {entry.status === "active" ? (
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => handleEliminateEntry(entry.id)}
                            data-testid={`button-eliminate-${entry.id}`}
                          >
                            <X className="h-4 w-4 mr-1" />
                            Eliminate
                          </Button>
                        ) : (
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => handleReinstateEntry(entry.id)}
                            data-testid={`button-reinstate-${entry.id}`}
                          >
                            <Check className="h-4 w-4 mr-1" />
                            Reinstate
                          </Button>
                        )}
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>

        {pool.entryFee || pool.prizePool || pool.notes ? (
          <Card>
            <CardHeader>
              <CardTitle>Pool Details</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {pool.entryFee && (
                <div className="flex items-center gap-2">
                  <CircleDot className="h-4 w-4 text-muted-foreground" />
                  <span className="font-medium">Entry Fee:</span>
                  <span>{pool.entryFee}</span>
                </div>
              )}
              {pool.prizePool && (
                <div className="flex items-center gap-2">
                  <Trophy className="h-4 w-4 text-muted-foreground" />
                  <span className="font-medium">Prize Pool:</span>
                  <span>{pool.prizePool}</span>
                </div>
              )}
              {pool.notes && (
                <div>
                  <span className="font-medium">Notes:</span>
                  <p className="text-muted-foreground mt-1">{pool.notes}</p>
                </div>
              )}
            </CardContent>
          </Card>
        ) : null}
      </main>
    </div>
  );
}

client/src/pages/golf/GolfPoolSignup.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation, useParams, Link } from "wouter";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { ArrowLeft, Trophy, Users, DollarSign, Calendar, Check, LogIn } from "lucide-react";
import { isUnauthorizedError } from "@/lib/authUtils";

type GolfPoolPublic = {
  id: string;
  name: string;
  slug: string | null;
  season: number;
  entryFee: string | null;
  currentWeek: number;
  entryCount: number;
  status: string;
};

type Participant = {
  id: string;
  email: string;
  firstName: string | null;
  lastName: string | null;
};

function useParticipantAuth() {
  const { data: participant, isLoading, error } = useQuery<Participant>({
    queryKey: ["/api/participant/user"],
    retry: false,
  });

  const isAuthenticated = !!participant && !error;
  return { participant, isLoading, isAuthenticated };
}

export default function GolfPoolSignup() {
  const [, setLocation] = useLocation();
  const params = useParams();
  const poolId = params.poolId || "";
  const { toast } = useToast();
  const { participant, isLoading: authLoading, isAuthenticated } = useParticipantAuth();
  const [entryName, setEntryName] = useState("");

  const { data: pool, isLoading: poolLoading, error: poolError } = useQuery<GolfPoolPublic>({
    queryKey: ["/api/public/golf/pools", poolId],
    queryFn: async () => {
      const response = await fetch(`/api/public/golf/pools/${poolId}`);
      if (!response.ok) throw new Error("Pool not found");
      return response.json();
    },
  });

  const signupMutation = useMutation({
    mutationFn: async (data: { entryName: string }) => {
      return await apiRequest("POST", `/api/participant/golf/pools/${poolId}/signup`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/participant/golf/entries"] });
      toast({ title: "Welcome to the Pool!", description: "You've successfully signed up." });
      setLocation("/join");
    },
    onError: (error: any) => {
      toast({ title: "Signup Failed", description: error.message, variant: "destructive" });
    },
  });

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryName.trim()) {
      signupMutation.mutate({ entryName: entryName.trim() });
    }
  };

  if (poolLoading || authLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <p className="text-muted-foreground">Loading...</p>
      </div>
    );
  }

  if (poolError || !pool) {
    return (
      <div className="min-h-screen bg-background">
        <div className="container mx-auto px-4 py-12 text-center">
          <h1 className="text-2xl font-bold mb-4">Pool Not Found</h1>
          <p className="text-muted-foreground mb-6">This pool doesn't exist or is no longer available.</p>
          <Link href="/golfsurvivor">
            <Button>Back to Golf Survivor</Button>
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between">
          <Link href="/">
            <span className="text-xl font-bold cursor-pointer" data-testid="link-home">South Bay Pools</span>
          </Link>
          {isAuthenticated && (
            <span className="text-sm text-muted-foreground">{participant?.email}</span>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-lg">
        <Link href="/golfsurvivor">
          <Button variant="ghost" size="sm" className="mb-4" data-testid="button-back">
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Golf Survivor
          </Button>
        </Link>

        <Card className="mb-6">
          <CardHeader className="text-center">
            <div className="h-16 w-16 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center mx-auto mb-4">
              <Trophy className="h-8 w-8 text-green-600 dark:text-green-400" />
            </div>
            <CardTitle className="text-2xl">{pool.name}</CardTitle>
            <CardDescription>
              {pool.season} PGA Tour Season
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-3 gap-4 text-center mb-6">
              <div>
                <Users className="h-5 w-5 mx-auto mb-1 text-muted-foreground" />
                <p className="text-lg font-semibold">{pool.entryCount}</p>
                <p className="text-xs text-muted-foreground">Entries</p>
              </div>
              <div>
                <DollarSign className="h-5 w-5 mx-auto mb-1 text-muted-foreground" />
                <p className="text-lg font-semibold">{pool.entryFee ? `$${pool.entryFee}` : "Free"}</p>
                <p className="text-xs text-muted-foreground">Entry Fee</p>
              </div>
              <div>
                <Calendar className="h-5 w-5 mx-auto mb-1 text-muted-foreground" />
                <p className="text-lg font-semibold">Week {pool.currentWeek}</p>
                <p className="text-xs text-muted-foreground">Current</p>
              </div>
            </div>

            {pool.status !== "open" ? (
              <div className="text-center py-4">
                <Badge variant="secondary" className="mb-2">Registration Closed</Badge>
                <p className="text-sm text-muted-foreground">This pool is no longer accepting new entries.</p>
              </div>
            ) : !isAuthenticated ? (
              <div className="text-center py-4">
                <p className="text-muted-foreground mb-4">Sign in to join this pool</p>
                <a href="/api/login" data-testid="button-sign-in">
                  <Button size="lg" className="w-full gap-2">
                    <LogIn className="h-5 w-5" />
                    Sign In to Join
                  </Button>
                </a>
                <a href="/api/login/select-account" className="block mt-2">
                  <Button variant="ghost" size="sm" className="w-full">
                    Use a Different Account
                  </Button>
                </a>
              </div>
            ) : (
              <form onSubmit={handleSignup} className="space-y-4">
                <div>
                  <Label htmlFor="entryName">Your Entry Name</Label>
                  <Input
                    id="entryName"
                    value={entryName}
                    onChange={(e) => setEntryName(e.target.value)}
                    placeholder="e.g., John's Pick, Lucky 7"
                    data-testid="input-entry-name"
                  />
                  <p className="text-xs text-muted-foreground mt-1">
                    This is how your entry will appear on the leaderboard
                  </p>
                </div>
                <Button
                  type="submit"
                  size="lg"
                  className="w-full gap-2"
                  disabled={!entryName.trim() || signupMutation.isPending}
                  data-testid="button-signup"
                >
                  {signupMutation.isPending ? (
                    "Joining..."
                  ) : (
                    <>
                      <Check className="h-5 w-5" />
                      Join Pool
                    </>
                  )}
                </Button>
              </form>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="text-lg">How It Works</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3 text-sm">
            <div className="flex gap-3">
              <div className="h-6 w-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-xs font-bold shrink-0">1</div>
              <p>Pick one golfer each week who you think will make the cut</p>
            </div>
            <div className="flex gap-3">
              <div className="h-6 w-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-xs font-bold shrink-0">2</div>
              <p>If your golfer makes the cut, you survive to the next week</p>
            </div>
            <div className="flex gap-3">
              <div className="h-6 w-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-xs font-bold shrink-0">3</div>
              <p>You can only use each golfer once per season</p>
            </div>
            <div className="flex gap-3">
              <div className="h-6 w-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-xs font-bold shrink-0">4</div>
              <p>Last one standing wins the pot!</p>
            </div>
          </CardContent>
        </Card>
      </main>
    </div>
  );
}

client/src/pages/golf/NewGolfPool.tsx.content:
import { useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useToast } from "@/hooks/use-toast";
import TopNav from "@/components/TopNav";
import { ArrowLeft } from "lucide-react";

const formSchema = z.object({
  name: z.string().min(1, "Pool name is required").max(100, "Name must be 100 characters or less"),
  slug: z.union([
    z.string()
      .max(100, "URL slug must be 100 characters or less")
      .regex(/^[a-z0-9-]+$/, "URL slug can only contain lowercase letters, numbers, and hyphens"),
    z.literal(''),
  ]).optional(),
  season: z.number().min(2020).max(2100),
  entryFee: z.string().optional(),
  prizePool: z.string().optional(),
  pickDeadlineHours: z.number().min(0).max(72).optional(),
  notes: z.string().optional(),
});

type FormData = z.infer<typeof formSchema>;

export default function NewGolfPool() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: "",
      slug: "",
      season: new Date().getFullYear(),
      entryFee: "",
      prizePool: "",
      pickDeadlineHours: 0,
      notes: "",
    },
  });

  const createPoolMutation = useMutation({
    mutationFn: async (data: FormData) => {
      return await apiRequest("POST", "/api/golf/pools", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/golf/pools"] });
      toast({
        title: "Pool Created",
        description: "Your Golf Survivor pool has been created successfully.",
      });
      setLocation("/admin/golf");
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to create pool",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (data: FormData) => {
    createPoolMutation.mutate(data);
  };

  return (
    <div className="min-h-screen bg-background">
      <TopNav title="Golf Survivor" />

      <main className="max-w-2xl mx-auto px-6 py-8">
        <div className="mb-6">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setLocation("/admin/golf")}
            className="mb-4"
            data-testid="button-back"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Dashboard
          </Button>
          <h2 className="text-3xl font-semibold">New Golf Survivor Pool</h2>
          <p className="text-muted-foreground mt-2">
            Create a new survivor-style pool for the PGA Tour season
          </p>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Pool Settings</CardTitle>
            <CardDescription>
              Configure your pool's basic settings and rules
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6">
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Pool Name</FormLabel>
                      <FormControl>
                        <Input
                          placeholder="e.g., 2025 PGA Survivor Pool"
                          {...field}
                          data-testid="input-pool-name"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="slug"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>URL Slug (Optional)</FormLabel>
                      <FormControl>
                        <Input
                          placeholder="e.g., pga-survivor-2025"
                          {...field}
                          data-testid="input-pool-slug"
                        />
                      </FormControl>
                      <FormDescription>
                        Leave blank to use a random ID. Only lowercase letters, numbers, and hyphens.
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="season"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Season</FormLabel>
                      <Select
                        value={field.value?.toString()}
                        onValueChange={(v) => field.onChange(parseInt(v))}
                      >
                        <FormControl>
                          <SelectTrigger data-testid="select-season">
                            <SelectValue placeholder="Select season" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="2025">2025</SelectItem>
                          <SelectItem value="2026">2026</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="entryFee"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Entry Fee (Optional)</FormLabel>
                        <FormControl>
                          <Input
                            placeholder="e.g., $50"
                            {...field}
                            data-testid="input-entry-fee"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="prizePool"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Prize Pool (Optional)</FormLabel>
                        <FormControl>
                          <Input
                            placeholder="e.g., $500"
                            {...field}
                            data-testid="input-prize-pool"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="pickDeadlineHours"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Pick Deadline</FormLabel>
                      <Select
                        value={field.value?.toString()}
                        onValueChange={(v) => field.onChange(parseInt(v))}
                      >
                        <FormControl>
                          <SelectTrigger data-testid="select-deadline">
                            <SelectValue placeholder="Select deadline" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="0">At tournament start</SelectItem>
                          <SelectItem value="1">1 hour before</SelectItem>
                          <SelectItem value="2">2 hours before</SelectItem>
                          <SelectItem value="6">6 hours before</SelectItem>
                          <SelectItem value="12">12 hours before</SelectItem>
                          <SelectItem value="24">24 hours before</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormDescription>
                        When picks are due relative to tournament start
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="notes"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Notes (Optional)</FormLabel>
                      <FormControl>
                        <Textarea
                          placeholder="Any additional rules or information for participants..."
                          className="resize-none"
                          {...field}
                          data-testid="input-notes"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="flex gap-4 pt-4">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => setLocation("/admin/golf")}
                    data-testid="button-cancel"
                  >
                    Cancel
                  </Button>
                  <Button
                    type="submit"
                    disabled={createPoolMutation.isPending}
                    data-testid="button-create-pool"
                  >
                    {createPoolMutation.isPending ? "Creating..." : "Create Pool"}
                  </Button>
                </div>
              </form>
            </Form>
          </CardContent>
        </Card>
      </main>
    </div>
  );
}

